#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

print header;

my $log_dir = "/path/to/log/directory";
my $logfile = param('logfile');

if (defined $logfile && -e "$log_dir/$logfile") {
    open(my $fh, "<", "$log_dir/$logfile") or die "Cannot open log file: $!";
    print start_html("Log Viewer");
    while (<$fh>) {
        print escapeHTML($_);
    }
    close($fh);
    print end_html;
} else {
    print h1("Log File Not Found or Invalid");
}